    flow:    { color: '#94a3b8', label: 'Flow' },
    string:  { color: '#34d399', label: 'String' },
    number:  { color: '#60a5fa', label: 'Number' },
    boolean: { color: '#f87171', label: 'Boolean' },
    object:  { color: '#c084fc', label: 'Object' },
    array:   { color: '#fb923c', label: 'Array' },
    any:     { color: '#94a3b8', label: 'Any' },
