/**
 * @fileoverview NodeBaseEditor state — internal data operations,
 * undo / redo command pattern, connection & group management.
 *
 * Imports: constants, helpers, view (no circular deps — view does
 * not import from state).
 *
 * @module module/NodeBaseEditor/state
 */

import razyui from '../../index.js';
import { SVG_NS, PART } from './constants.js';
import { portColor, mk, serializeNode } from './helpers.js';
import {
    renderNodeEl, updateConnectionPath,
    updateConnectionsForNode, scheduleMinimapRender,
    updateAllConnections,
} from './view.js';


// ══════════════════════════════════════════════════════════════════
//  Undo / Redo
// ══════════════════════════════════════════════════════════════════

/**
 * Push a command onto the undo stack (clears redo).
 * @param {Object} ctx
 * @param {Object} cmd - { type, undo(), redo() }
 */
export function pushCommand(ctx, cmd) {
    ctx.undoStack.push(cmd);
    if (ctx.undoStack.length > ctx.maxHistory) ctx.undoStack.shift();
    ctx.redoStack.length = 0;
}

/**
 * Undo the last command.
 * @param {Object} ctx
 */
export function undoLast(ctx) {
    const cmd = ctx.undoStack.pop();
    if (!cmd) return;
    cmd.undo();
    ctx.redoStack.push(cmd);
    updateAllConnections(ctx);
    scheduleMinimapRender(ctx);
    onChange(ctx);
}

/**
 * Redo the last undone command.
 * @param {Object} ctx
 */
export function redoLast(ctx) {
    const cmd = ctx.redoStack.pop();
    if (!cmd) return;
    cmd.redo();
    ctx.undoStack.push(cmd);
    updateAllConnections(ctx);
    scheduleMinimapRender(ctx);
    onChange(ctx);
}

/**
 * Call the onChange callback if configured.
 * @param {Object} ctx
 */
export function onChange(ctx) {
    ctx.config.onChange?.();
}


// ══════════════════════════════════════════════════════════════════
//  Node internal operations
// ══════════════════════════════════════════════════════════════════

/**
 * Create a node object, render it, and store it.
 * @param {Object} ctx
 * @param {string} id
 * @param {string} type
 * @param {number} x
 * @param {number} y
 * @param {string} label
 * @param {Object} data
 * @returns {Object} The node object.
 */
export function addNodeInternal(ctx, id, type, x, y, label, data) {
    const def = ctx.nodeTypes.get(type);
    const node = {
        id, type, label: label || def?.label || type,
        x, y,
        data: data || {},
        collapsed: false,
        el: null,
        headerEl: null,
        bodyEl: null,
        inputPorts: new Map(),
        outputPorts: new Map(),
    };
    ctx.nodes.set(id, node);
    renderNodeEl(ctx, node, def);
    ctx.config.onNodeAdd?.(serializeNode(node));
    return node;
}

/**
 * Remove a node without undo.
 * @param {Object} ctx
 * @param {string} id
 */
export function removeNodeInternal(ctx, id) {
    const node = ctx.nodes.get(id);
    if (!node) return;
    node.el?.[0]?.remove();
    ctx.nodes.delete(id);
    ctx.selectedNodes.delete(id);
    ctx.config.onNodeRemove?.({ id });
    scheduleMinimapRender(ctx);
}


// ══════════════════════════════════════════════════════════════════
//  Connection internal operations
// ══════════════════════════════════════════════════════════════════

/**
 * Create a connection object and render its SVG path.
 * @param {Object} ctx
 * @param {string} id
 * @param {string} fromNodeId
 * @param {string} fromPortId
 * @param {string} toNodeId
 * @param {string} toPortId
 */
export function connectInternal(ctx, id, fromNodeId, fromPortId, toNodeId, toPortId) {
    const fromPort = ctx.nodes.get(fromNodeId)?.outputPorts.get(fromPortId);
    const g = razyui.el('g', { class: 'nbe-conn', 'data-conn-id': id });
    PART.CONN.apply(g);
    const hit = razyui.el('path', {
        class: 'nbe-conn-hit', fill: 'none',
        stroke: 'transparent', 'stroke-width': '14', 'pointer-events': 'stroke',
    });
    PART.CONN_HIT.apply(hit);
    const line = razyui.el('path', {
        class: 'nbe-conn-line', fill: 'none',
        stroke: portColor(fromPort?.type || 'any'), 'stroke-width': '2', 'pointer-events': 'none',
    });
    PART.CONN_LINE.apply(line);
    g.append(hit).append(line);
    ctx.svg.append(g);
    const conn = {
        id,
        from: { nodeId: fromNodeId, portId: fromPortId },
        to: { nodeId: toNodeId, portId: toPortId },
        el: g, path: line, hitPath: hit,
    };
    ctx.connections.set(id, conn);
    updateConnectionPath(ctx, conn);
    ctx.config.onConnect?.({ id, from: { ...conn.from }, to: { ...conn.to } });
}

/**
 * Remove a connection without undo.
 * @param {Object} ctx
 * @param {string} id
 */
export function disconnectInternal(ctx, id) {
    const conn = ctx.connections.get(id);
    if (!conn) return;
    conn.el?.[0]?.remove();
    ctx.connections.delete(id);
    ctx.selectedConns.delete(id);
    ctx.config.onDisconnect?.({ id, from: { ...conn.from }, to: { ...conn.to } });
    scheduleMinimapRender(ctx);
}

/**
 * If the target input port already has a data connection, remove it.
 * Flow ports allow multiple connections, data ports do not.
 * @param {Object} ctx
 * @param {string} toNodeId
 * @param {string} toPortId
 */
export function autoReplaceInput(ctx, toNodeId, toPortId) {
    const port = ctx.nodes.get(toNodeId)?.inputPorts.get(toPortId);
    if (!port || port.type === 'flow') return;
    for (const conn of ctx.connections.values()) {
        if (conn.to.nodeId === toNodeId && conn.to.portId === toPortId) {
            disconnectInternal(ctx, conn.id);
            return;
        }
    }
}


// ══════════════════════════════════════════════════════════════════
//  Group internal operations
// ══════════════════════════════════════════════════════════════════

/**
 * Create and render a group.
 * @param {Object} ctx
 * @param {string} id
 * @param {string} label
 * @param {number} x
 * @param {number} y
 * @param {number} w
 * @param {number} h
 * @param {string} color
 */
export function addGroupInternal(ctx, id, label, x, y, w, h, color) {
    const el = mk('div', 'nbe-group');
    PART.GROUP.apply(el);
    el.data('groupId', id)
      .css({
          left: x + 'px',
          top: y + 'px',
          width: w + 'px',
          height: h + 'px',
          'border-color': color,
          'background-color': color + '22',
      });
    const lbl = mk('div', 'nbe-group-label');
    PART.GROUP_LABEL.apply(lbl);
    lbl.text(label);
    el.append(lbl);
    // Resize handle
    const rh = mk('div', 'nbe-group-resize');
    PART.GROUP_RESIZE.apply(rh);
    el.append(rh);
    // Insert before nodes (groups sit behind)
    ctx.canvas[0].insertBefore(el[0], ctx.canvas.find('.nbe-node')[0] || null);
    const group = { id, label, x, y, width: w, height: h, color, el, labelEl: lbl };
    ctx.groups.set(id, group);
    scheduleMinimapRender(ctx);
}

/**
 * Remove a group without undo.
 * @param {Object} ctx
 * @param {string} id
 */
export function removeGroupInternal(ctx, id) {
    const g = ctx.groups.get(id);
    if (!g) return;
    g.el?.[0]?.remove();
    ctx.groups.delete(id);
    ctx.selectedGroups.delete(id);
}


// ══════════════════════════════════════════════════════════════════
//  Position restoration
// ══════════════════════════════════════════════════════════════════

/**
 * Restore node positions from a Map (used by undo / redo).
 * @param {Object} ctx
 * @param {Map} posMap
 */
export function restoreNodePositions(ctx, posMap) {
    for (const [nid, pos] of posMap) {
        const node = ctx.nodes.get(nid);
        if (!node) continue;
        node.x = pos.x;
        node.y = pos.y;
        node.el.css('left', pos.x + 'px');
        node.el.css('top', pos.y + 'px');
        updateConnectionsForNode(ctx, nid);
    }
    scheduleMinimapRender(ctx);
}
