/**
 * @fileoverview NodeBaseEditor events — centralised event binding
 * (pointer, keyboard, drag, context menu, selection, etc.).
 *
 * @module module/NodeBaseEditor/events
 */

import { DEFAULTS } from './constants.js';
import Icons from '../Icons.js';
import {
    screenToCanvas, viewportPos as getViewportPos, snap as snapVal,
    getPortPos, bezier, findPortNearPoint, nodesInGroup,
    serializeNode, getContentBounds,
} from './helpers.js';
import { sharedResizeObserver } from '../shared/SharedResizeObserver.js';
import {
    applyTransform, scheduleMinimapRender,
    updateConnectionsForNode, createTempWire,
    renderContextMenu, hideContextMenu,
} from './view.js';
import {
    pushCommand, onChange,
    addNodeInternal, removeNodeInternal,
    connectInternal, disconnectInternal,
    addGroupInternal, removeGroupInternal,
    restoreNodePositions,
} from './state.js';
import razyui from '../../index.js';


// ══════════════════════════════════════════════════════════════════
//  Main event binding
// ══════════════════════════════════════════════════════════════════

/**
 * Bind all interactive event handlers.
 * @param {Object} ctx - Context bridge.
 */
export function bindEvents(ctx) {
    const viewport = ctx.el.find('.nbe-viewport')[0];

    const $viewport = razyui(viewport);

    // ── Wheel zoom ──
    ctx.onWheel = (e) => {
        e.preventDefault();
        const factor = e.deltaY < 0 ? DEFAULTS.wheelFactor : 1 / DEFAULTS.wheelFactor;
        const rect = viewport.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;
        zoomAtPoint(ctx, mx, my, ctx.zoom * factor);
    };
    $viewport.on('wheel', ctx.onWheel, { passive: false });

    // Drop from node panel
    $viewport.on('dragover', (e) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'copy';
    });
    $viewport.on('drop', (e) => {
        e.preventDefault();
        const type = e.dataTransfer.getData('text/plain');
        if (!type || !ctx.nodeTypes.has(type)) return;
        const vp = getViewportPos(ctx.el, e);
        const pos = screenToCanvas(ctx.panX, ctx.panY, ctx.zoom, vp.x, vp.y);
        ctx.addNode(type, snapVal(pos.x, ctx.gridSize, ctx.snapEnabled), snapVal(pos.y, ctx.gridSize, ctx.snapEnabled));
    });

    // ── Viewport pointer down (supports mouse + touch) ──
    $viewport.on('pointerdown', (e) => {
        hideContextMenu(ctx);

        // Middle-drag pan
        if (e.button === 1) {
            e.preventDefault();
            ctx.panDrag = { sx: e.clientX, sy: e.clientY, px: ctx.panX, py: ctx.panY };
            return;
        }

        // Space+left = pan
        if (e.button === 0 && ctx.spaceHeld) {
            e.preventDefault();
            ctx.panDrag = { sx: e.clientX, sy: e.clientY, px: ctx.panX, py: ctx.panY };
            return;
        }

        // Right-click = context menu
        if (e.button === 2) return;

        // Left-click
        if (e.button === 0) {
            const target = razyui(e.target);

            // Ignore clicks originating from the node panel (HTML5 drag source)
            if (target.closest('.nbe-node-panel').length) return;

            const portDot = target.closest('.nbe-port-dot');
            const nodeEl = target.closest('.nbe-node');
            const groupEl = target.closest('.nbe-group');
            const connHit = target.closest('.nbe-conn-hit');

            if (portDot.length) {
                e.preventDefault();
                e.stopPropagation();
                startWireDrag(ctx, portDot[0], e);
                return;
            }

            if (connHit.length) {
                e.preventDefault();
                const connId = connHit.closest('.nbe-conn').attr('data-conn-id');
                if (connId) selectConnection(ctx, connId, e.ctrlKey || e.metaKey);
                return;
            }

            if (nodeEl.length) {
                e.preventDefault();
                const nodeId = nodeEl.data('nodeId');
                if (nodeId) {
                    if (!e.ctrlKey && !e.metaKey && !ctx.selectedNodes.has(nodeId)) {
                        clearSelection(ctx);
                    }
                    selectNode(ctx, nodeId, true);
                    startNodeDrag(ctx, nodeId, e);
                }
                return;
            }

            if (groupEl.length) {
                e.preventDefault();
                const gid = groupEl.data('groupId');
                const handle = target.closest('.nbe-group-resize');
                if (handle.length && gid) {
                    startGroupResize(ctx, gid, e);
                    return;
                }
                if (gid) {
                    if (!e.ctrlKey && !e.metaKey) clearSelection(ctx);
                    selectGroup(ctx, gid, true);
                    startGroupDrag(ctx, gid, e);
                }
                return;
            }

            // Click on empty canvas → start box select (or click-deselect)
            if (!e.ctrlKey && !e.metaKey) clearSelection(ctx);
            startBoxSelect(ctx, e, viewport);
        }
    });

    // ── Context menu ──
    $viewport.on('contextmenu', (e) => {
        e.preventDefault();
        const target = razyui(e.target);
        const nodeEl = target.closest('.nbe-node');
        const groupEl = target.closest('.nbe-group');
        const connHit = target.closest('.nbe-conn-hit');
        if (nodeEl.length) {
            showNodeContextMenu(ctx, nodeEl.data('nodeId'), e);
        } else if (groupEl.length) {
            showGroupContextMenu(ctx, groupEl.data('groupId'), e);
        } else if (connHit.length) {
            const connId = connHit.closest('.nbe-conn').attr('data-conn-id');
            if (connId) showConnectionContextMenu(ctx, connId, e);
        } else {
            showCanvasContextMenu(ctx, e);
        }
    });

    // ── Document pointer move / up (supports mouse + touch) ──
    ctx.onMouseMove = (e) => {
        if (ctx.panDrag) handlePanMove(ctx, e);
        else if (ctx.nodeDrag) handleNodeDragMove(ctx, e);
        else if (ctx.wireDrag) handleWireDragMove(ctx, e);
        else if (ctx.boxSelect) handleBoxSelectMove(ctx, e, viewport);
        else if (ctx.groupDrag) handleGroupDragMove(ctx, e);
        else if (ctx.groupResize) handleGroupResizeMove(ctx, e);
    };
    ctx.onMouseUp = (e) => {
        if (ctx.panDrag) { ctx.panDrag = null; return; }
        if (ctx.nodeDrag) { endNodeDrag(ctx); return; }
        if (ctx.wireDrag) { endWireDrag(ctx, e); return; }
        if (ctx.boxSelect) { endBoxSelect(ctx, viewport); return; }
        if (ctx.groupDrag) { endGroupDrag(ctx); return; }
        if (ctx.groupResize) { endGroupResize(ctx); return; }
    };
    const $doc = razyui(document);
    const globalOpts = ctx.signal ? { signal: ctx.signal } : undefined;
    $doc.on('pointermove', ctx.onMouseMove, globalOpts);
    $doc.on('pointerup', ctx.onMouseUp, globalOpts);

    // ── Keyboard ──
    ctx.onKeyDown = (e) => {
        if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
        if (e.code === 'Space' && !ctx.spaceHeld) {
            ctx.spaceHeld = true;
            ctx.el.addClass('nbe-panning');
            e.preventDefault();
        }
        handleKeyDown(ctx, e);
    };
    ctx.onKeyUp = (e) => {
        if (e.code === 'Space') {
            ctx.spaceHeld = false;
            ctx.el.removeClass('nbe-panning');
        }
    };
    $doc.on('keydown', ctx.onKeyDown, globalOpts);
    $doc.on('keyup', ctx.onKeyUp, globalOpts);

    // ── Minimap interaction ──
    razyui(ctx.minimapCanvas).on('pointerdown', (e) => {
        handleMinimapClick(ctx, e);
    });

    // ── Resize observer (shared pool) ──
    sharedResizeObserver.observe(ctx.el[0], () => scheduleMinimapRender(ctx));
    ctx._resizeObservedEl = ctx.el[0];

    // Click outside context menu to close
    const captureOpts = ctx.signal ? { capture: true, signal: ctx.signal } : { capture: true };
    $doc.on('pointerdown', (e) => {
        if (ctx.contextMenuEl.css('display') !== 'none' && !ctx.contextMenuEl[0].contains(e.target)) {
            hideContextMenu(ctx);
        }
    }, captureOpts);

    // ── Toolbar click delegation ──
    razyui(ctx.toolbar).on('click', (e) => {
        const btn = razyui(e.target).closest('[data-action]');
        if (!btn.length) return;
        ctx.handleToolbarAction(btn.data('action'), btn[0]);
    });

    // ── Node panel: delegated dragstart + dblclick ──
    razyui(ctx.nodePanel).on('dragstart', (e) => {
        const item = razyui(e.target).closest('.nbe-np-item');
        if (!item.length) return;
        const type = item.data('nodeType');
        if (!type) return;
        e.dataTransfer.setData('text/plain', type);
        e.dataTransfer.effectAllowed = 'copy';
    });

    razyui(ctx.nodePanel).on('dblclick', (e) => {
        const item = razyui(e.target).closest('.nbe-np-item');
        if (!item.length) return;
        const type = item.data('nodeType');
        if (!type) return;
        const $vp = ctx.el.find('.nbe-viewport');
        const r = $vp[0].getBoundingClientRect();
        const cx = r.width / 2, cy = r.height / 2;
        const pos = screenToCanvas(ctx.panX, ctx.panY, ctx.zoom, cx, cy);
        ctx.addNode(type, snapVal(pos.x, ctx.gridSize, ctx.snapEnabled), snapVal(pos.y, ctx.gridSize, ctx.snapEnabled));
    });

    // ── Context menu: delegated click ──
    razyui(ctx.contextMenuEl).on('click', (e) => {
        const row = razyui(e.target).closest('.nbe-ctx-item');
        if (!row.length) return;
        hideContextMenu(ctx);
        row[0]._action?.();
    });
}


// ══════════════════════════════════════════════════════════════════
//  Zoom helpers
// ══════════════════════════════════════════════════════════════════

/**
 * Zoom the canvas towards/away from a viewport-relative point.
 * @param {Object} ctx
 * @param {number} px - Pointer X in viewport.
 * @param {number} py - Pointer Y in viewport.
 * @param {number} newZoom
 */
export function zoomAtPoint(ctx, px, py, newZoom) {
    const minZ = ctx.config.minZoom || DEFAULTS.minZoom;
    const maxZ = ctx.config.maxZoom || DEFAULTS.maxZoom;
    newZoom = Math.min(maxZ, Math.max(minZ, newZoom));
    const cx = (px - ctx.panX) / ctx.zoom;
    const cy = (py - ctx.panY) / ctx.zoom;
    ctx.panX = px - cx * newZoom;
    ctx.panY = py - cy * newZoom;
    ctx.zoom = newZoom;
    applyTransform(ctx);
}


// ══════════════════════════════════════════════════════════════════
//  Selection helpers
// ══════════════════════════════════════════════════════════════════

/**
 * Select a node (add to or replace selection).
 * @param {Object} ctx
 * @param {string} id
 * @param {boolean} [add=false]
 */
export function selectNode(ctx, id, add = false) {
    if (!add) clearSelection(ctx);
    ctx.selectedNodes.add(id);
    ctx.nodes.get(id)?.el?.addClass('is-selected');
    ctx.config.onSelect?.([...ctx.selectedNodes]);
}

/** Select a connection. */
export function selectConnection(ctx, connId, add = false) {
    if (!add) clearSelection(ctx);
    ctx.selectedConns.add(connId);
    const conn = ctx.connections.get(connId);
    conn?.path?.addClass('is-selected');
    conn?.el?.addClass('is-selected');
}

/** Select a group. */
export function selectGroup(ctx, gid, add = false) {
    if (!add) clearSelection(ctx);
    ctx.selectedGroups.add(gid);
    ctx.groups.get(gid)?.el?.addClass('is-selected');
}

/** Clear all selection. */
export function clearSelection(ctx) {
    for (const id of ctx.selectedNodes) ctx.nodes.get(id)?.el?.removeClass('is-selected');
    for (const id of ctx.selectedConns) {
        const c = ctx.connections.get(id);
        c?.path?.removeClass('is-selected');
        c?.el?.removeClass('is-selected');
    }
    for (const id of ctx.selectedGroups) ctx.groups.get(id)?.el?.removeClass('is-selected');
    ctx.selectedNodes.clear();
    ctx.selectedConns.clear();
    ctx.selectedGroups.clear();
}

/** Select all nodes. */
export function selectAll(ctx) {
    for (const node of ctx.nodes.values()) {
        ctx.selectedNodes.add(node.id);
        node.el?.addClass('is-selected');
    }
    ctx.config.onSelect?.([...ctx.selectedNodes]);
}


// ══════════════════════════════════════════════════════════════════
//  Pan
// ══════════════════════════════════════════════════════════════════

function handlePanMove(ctx, e) {
    if (!ctx.panDrag) return;
    ctx.panX = ctx.panDrag.px + (e.clientX - ctx.panDrag.sx);
    ctx.panY = ctx.panDrag.py + (e.clientY - ctx.panDrag.sy);
    applyTransform(ctx);
}


// ══════════════════════════════════════════════════════════════════
//  Wire Drag (port → port connection creation)
// ══════════════════════════════════════════════════════════════════

function startWireDrag(ctx, dot, e) {
    const nodeId = dot.dataset.nodeId;
    const portId = dot.dataset.portName;
    const dir = dot.dataset.dir;
    const isOutput = dir === 'output';

    // If dragging from an input that already has a connection, detach it
    if (!isOutput) {
        for (const conn of ctx.connections.values()) {
            if (conn.to.nodeId === nodeId && conn.to.portId === portId) {
                const fromNodeId = conn.from.nodeId;
                const fromPortId = conn.from.portId;
                disconnectInternal(ctx, conn.id);
                ctx.wireDrag = { fromNodeId, fromPortId, isOutput: true, tempPath: null };
                createTempWire(ctx);
                onChange(ctx);
                return;
            }
        }
    }

    ctx.wireDrag = { fromNodeId: nodeId, fromPortId: portId, isOutput, tempPath: null };
    createTempWire(ctx);
}

function handleWireDragMove(ctx, e) {
    if (!ctx.wireDrag?.tempPath) return;
    const vp = getViewportPos(ctx.el, e);
    const mouse = screenToCanvas(ctx.panX, ctx.panY, ctx.zoom, vp.x, vp.y);
    const from = getPortPos(ctx.nodes, ctx.wireDrag.fromNodeId, ctx.wireDrag.fromPortId);
    if (!from) return;

    let d;
    if (ctx.wireDrag.isOutput) {
        d = bezier(from.x, from.y, mouse.x, mouse.y);
    } else {
        d = bezier(mouse.x, mouse.y, from.x, from.y);
    }
    ctx.wireDrag.tempPath.attr('d', d);

    // Highlight nearest compatible port
    highlightNearestPort(ctx, e.clientX, e.clientY);
}

function endWireDrag(ctx, e) {
    if (!ctx.wireDrag) return;
    const wd = ctx.wireDrag;
    wd.tempPath?.[0]?.remove();
    clearPortHighlights(ctx);

    const wantInput = wd.isOutput;
    const target = findPortNearPoint(ctx.nodes, ctx.wireDrag, e.clientX, e.clientY, wd.fromNodeId, wantInput);
    if (target) {
        if (wd.isOutput) {
            ctx.connect(wd.fromNodeId, wd.fromPortId, target.nodeId, target.portId);
        } else {
            ctx.connect(target.nodeId, target.portId, wd.fromNodeId, wd.fromPortId);
        }
    }
    ctx.wireDrag = null;
}

function highlightNearestPort(ctx, cx, cy) {
    clearPortHighlights(ctx);
    if (!ctx.wireDrag) return;
    const wantInput = ctx.wireDrag.isOutput;
    const target = findPortNearPoint(ctx.nodes, ctx.wireDrag, cx, cy, ctx.wireDrag.fromNodeId, wantInput);
    if (target) {
        const node = ctx.nodes.get(target.nodeId);
        const port = wantInput ? node?.inputPorts.get(target.portId) : node?.outputPorts.get(target.portId);
        port?.dot?.addClass('is-highlight');
    }
}

function clearPortHighlights(ctx) {
    for (const node of ctx.nodes.values()) {
        for (const p of node.inputPorts.values()) p.dot.removeClass('is-highlight');
        for (const p of node.outputPorts.values()) p.dot.removeClass('is-highlight');
    }
}


// ══════════════════════════════════════════════════════════════════
//  Node Drag
// ══════════════════════════════════════════════════════════════════

function startNodeDrag(ctx, nodeId, e) {
    const ids = ctx.selectedNodes.has(nodeId) ? [...ctx.selectedNodes] : [nodeId];
    const origPositions = new Map();
    for (const nid of ids) {
        const n = ctx.nodes.get(nid);
        if (n) origPositions.set(nid, { x: n.x, y: n.y });
    }
    ctx.nodeDrag = { ids, origPositions, startClientX: e.clientX, startClientY: e.clientY };
}

function handleNodeDragMove(ctx, e) {
    if (!ctx.nodeDrag) return;
    const nd = ctx.nodeDrag;
    const dx = (e.clientX - nd.startClientX) / ctx.zoom;
    const dy = (e.clientY - nd.startClientY) / ctx.zoom;
    for (const nid of nd.ids) {
        const node = ctx.nodes.get(nid);
        const orig = nd.origPositions.get(nid);
        if (!node || !orig) continue;
        node.x = snapVal(orig.x + dx, ctx.gridSize, ctx.snapEnabled);
        node.y = snapVal(orig.y + dy, ctx.gridSize, ctx.snapEnabled);
        node.el.css('left', node.x + 'px').css('top', node.y + 'px');
        updateConnectionsForNode(ctx, nid);
    }
    scheduleMinimapRender(ctx);
}

function endNodeDrag(ctx) {
    if (!ctx.nodeDrag) return;
    const nd = ctx.nodeDrag;
    const newPositions = new Map();
    let moved = false;
    for (const nid of nd.ids) {
        const node = ctx.nodes.get(nid);
        if (!node) continue;
        newPositions.set(nid, { x: node.x, y: node.y });
        const orig = nd.origPositions.get(nid);
        if (orig && (orig.x !== node.x || orig.y !== node.y)) moved = true;
    }
    if (moved) {
        const origP = new Map(nd.origPositions);
        const newP = new Map(newPositions);
        pushCommand(ctx, {
            type: 'moveNodes',
            undo: () => restoreNodePositions(ctx, origP),
            redo: () => restoreNodePositions(ctx, newP),
        });
        onChange(ctx);
    }
    ctx.nodeDrag = null;
}


// ══════════════════════════════════════════════════════════════════
//  Box Select
// ══════════════════════════════════════════════════════════════════

function startBoxSelect(ctx, e, viewport) {
    const vr = viewport.getBoundingClientRect();
    ctx.boxSelect = { sx: e.clientX - vr.left, sy: e.clientY - vr.top };
    ctx.selBoxEl.css('display', 'block')
        .css('left', ctx.boxSelect.sx + 'px')
        .css('top', ctx.boxSelect.sy + 'px')
        .css('width', '0')
        .css('height', '0');
}

function handleBoxSelectMove(ctx, e, viewport) {
    if (!ctx.boxSelect) return;
    const vr = viewport.getBoundingClientRect();
    const cx = e.clientX - vr.left;
    const cy = e.clientY - vr.top;
    const x = Math.min(ctx.boxSelect.sx, cx);
    const y = Math.min(ctx.boxSelect.sy, cy);
    const w = Math.abs(cx - ctx.boxSelect.sx);
    const h = Math.abs(cy - ctx.boxSelect.sy);
    ctx.selBoxEl.css('left', x + 'px')
        .css('top', y + 'px')
        .css('width', w + 'px')
        .css('height', h + 'px');
}

function endBoxSelect(ctx, viewport) {
    if (!ctx.boxSelect) return;
    ctx.selBoxEl.css('display', 'none');
    const sx = parseFloat(ctx.selBoxEl.css('left'));
    const sy = parseFloat(ctx.selBoxEl.css('top'));
    const sw = parseFloat(ctx.selBoxEl.css('width'));
    const sh = parseFloat(ctx.selBoxEl.css('height'));
    if (sw > 4 || sh > 4) {
        const topLeft = screenToCanvas(ctx.panX, ctx.panY, ctx.zoom, sx, sy);
        const botRight = screenToCanvas(ctx.panX, ctx.panY, ctx.zoom, sx + sw, sy + sh);
        for (const node of ctx.nodes.values()) {
            const nw = node.el?.offsetWidth || DEFAULTS.nodeFallbackW;
            const nh = node.el?.offsetHeight || DEFAULTS.nodeFallbackH;
            if (node.x + nw > topLeft.x && node.x < botRight.x &&
                node.y + nh > topLeft.y && node.y < botRight.y) {
                selectNode(ctx, node.id, true);
            }
        }
    }
    ctx.boxSelect = null;
}


// ══════════════════════════════════════════════════════════════════
//  Group Drag & Resize
// ══════════════════════════════════════════════════════════════════

function startGroupDrag(ctx, gid, e) {
    const g = ctx.groups.get(gid);
    if (!g) return;
    const childIds = nodesInGroup(ctx.nodes, ctx.groups, gid);
    const origPositions = new Map();
    for (const nid of childIds) {
        const n = ctx.nodes.get(nid);
        if (n) origPositions.set(nid, { x: n.x, y: n.y });
    }
    ctx.groupDrag = {
        gid, origGX: g.x, origGY: g.y,
        childIds, origPositions,
        startCX: e.clientX, startCY: e.clientY,
    };
}

function handleGroupDragMove(ctx, e) {
    if (!ctx.groupDrag) return;
    const gd = ctx.groupDrag;
    const dx = (e.clientX - gd.startCX) / ctx.zoom;
    const dy = (e.clientY - gd.startCY) / ctx.zoom;
    const g = ctx.groups.get(gd.gid);
    if (g) {
        g.x = snapVal(gd.origGX + dx, ctx.gridSize, ctx.snapEnabled);
        g.y = snapVal(gd.origGY + dy, ctx.gridSize, ctx.snapEnabled);
        g.el.css('left', g.x + 'px').css('top', g.y + 'px');
    }
    for (const nid of gd.childIds) {
        const node = ctx.nodes.get(nid);
        const orig = gd.origPositions.get(nid);
        if (!node || !orig) continue;
        node.x = snapVal(orig.x + dx, ctx.gridSize, ctx.snapEnabled);
        node.y = snapVal(orig.y + dy, ctx.gridSize, ctx.snapEnabled);
        node.el.css('left', node.x + 'px').css('top', node.y + 'px');
        updateConnectionsForNode(ctx, nid);
    }
    scheduleMinimapRender(ctx);
}

function endGroupDrag(ctx) {
    if (!ctx.groupDrag) return;
    const gd = ctx.groupDrag;
    const g = ctx.groups.get(gd.gid);
    if (g && (g.x !== gd.origGX || g.y !== gd.origGY)) {
        const newGX = g.x, newGY = g.y;
        const newPositions = new Map();
        for (const nid of gd.childIds) {
            const n = ctx.nodes.get(nid);
            if (n) newPositions.set(nid, { x: n.x, y: n.y });
        }
        const origGX = gd.origGX, origGY = gd.origGY;
        const origP = new Map(gd.origPositions);
        const gid = gd.gid;
        pushCommand(ctx, {
            type: 'moveGroup',
            undo: () => {
                const gg = ctx.groups.get(gid);
                if (gg) { gg.x = origGX; gg.y = origGY; gg.el.css('left', origGX + 'px').css('top', origGY + 'px'); }
                restoreNodePositions(ctx, origP);
            },
            redo: () => {
                const gg = ctx.groups.get(gid);
                if (gg) { gg.x = newGX; gg.y = newGY; gg.el.css('left', newGX + 'px').css('top', newGY + 'px'); }
                restoreNodePositions(ctx, newPositions);
            },
        });
        onChange(ctx);
    }
    ctx.groupDrag = null;
}

function startGroupResize(ctx, gid, e) {
    const g = ctx.groups.get(gid);
    if (!g) return;
    ctx.groupResize = { gid, origW: g.width, origH: g.height, startCX: e.clientX, startCY: e.clientY };
}

function handleGroupResizeMove(ctx, e) {
    if (!ctx.groupResize) return;
    const gr = ctx.groupResize;
    const g = ctx.groups.get(gr.gid);
    if (!g) return;
    const dw = (e.clientX - gr.startCX) / ctx.zoom;
    const dh = (e.clientY - gr.startCY) / ctx.zoom;
    g.width = Math.max(DEFAULTS.groupMinW, snapVal(gr.origW + dw, ctx.gridSize, ctx.snapEnabled));
    g.height = Math.max(DEFAULTS.groupMinH, snapVal(gr.origH + dh, ctx.gridSize, ctx.snapEnabled));
    g.el.css('width', g.width + 'px').css('height', g.height + 'px');
}

function endGroupResize(ctx) {
    if (!ctx.groupResize) return;
    const gr = ctx.groupResize;
    const g = ctx.groups.get(gr.gid);
    if (g && (g.width !== gr.origW || g.height !== gr.origH)) {
        const newW = g.width, newH = g.height;
        const origW = gr.origW, origH = gr.origH;
        const gid = gr.gid;
        pushCommand(ctx, {
            type: 'resizeGroup',
            undo: () => { const gg = ctx.groups.get(gid); if (gg) { gg.width = origW; gg.height = origH; gg.el.css('width', origW + 'px').css('height', origH + 'px'); } },
            redo: () => { const gg = ctx.groups.get(gid); if (gg) { gg.width = newW; gg.height = newH; gg.el.css('width', newW + 'px').css('height', newH + 'px'); } },
        });
        onChange(ctx);
    }
    ctx.groupResize = null;
}


// ══════════════════════════════════════════════════════════════════
//  Keyboard
// ══════════════════════════════════════════════════════════════════

function handleKeyDown(ctx, e) {
    const ctrl = e.ctrlKey || e.metaKey;

    if (e.key === 'Delete' || e.key === 'Backspace') {
        e.preventDefault();
        deleteSelected(ctx);
        return;
    }
    if (ctrl && e.key === 'z') { e.preventDefault(); ctx.undo(); return; }
    if (ctrl && (e.key === 'y' || (e.shiftKey && e.key === 'Z'))) { e.preventDefault(); ctx.redo(); return; }
    if (ctrl && e.key === 'a') { e.preventDefault(); selectAll(ctx); return; }
    if (ctrl && e.key === 'g') { e.preventDefault(); groupFromSelection(ctx); return; }
    if (e.key === 'f' || e.key === 'F') { if (!ctrl) { ctx.fitView(); e.preventDefault(); } return; }
    if (e.key === '+' || e.key === '=') { ctx.zoomIn(); e.preventDefault(); return; }
    if (e.key === '-' || e.key === '_') { ctx.zoomOut(); e.preventDefault(); return; }
}


// ══════════════════════════════════════════════════════════════════
//  Delete / Duplicate / Group from Selection
// ══════════════════════════════════════════════════════════════════

/** Delete all selected nodes, connections, and groups. */
export function deleteSelected(ctx) {
    const cmds = [];
    for (const cid of ctx.selectedConns) {
        const conn = ctx.connections.get(cid);
        if (conn) {
            const snap = { id: conn.id, from: { ...conn.from }, to: { ...conn.to } };
            disconnectInternal(ctx, cid);
            cmds.push({
                undo: () => connectInternal(ctx, snap.id, snap.from.nodeId, snap.from.portId, snap.to.nodeId, snap.to.portId),
                redo: () => disconnectInternal(ctx, cid),
            });
        }
    }
    for (const nid of ctx.selectedNodes) {
        const node = ctx.nodes.get(nid);
        if (!node) continue;
        const attached = [];
        for (const c of ctx.connections.values()) {
            if (c.from.nodeId === nid || c.to.nodeId === nid) {
                attached.push({ id: c.id, from: { ...c.from }, to: { ...c.to } });
            }
        }
        const nodeSnap = serializeNode(node);
        for (const c of attached) disconnectInternal(ctx, c.id);
        removeNodeInternal(ctx, nid);
        cmds.push({
            undo: () => {
                addNodeInternal(ctx, nodeSnap.id, nodeSnap.type, nodeSnap.x, nodeSnap.y, nodeSnap.label, { ...nodeSnap.data });
                for (const c of attached) connectInternal(ctx, c.id, c.from.nodeId, c.from.portId, c.to.nodeId, c.to.portId);
            },
            redo: () => {
                for (const c of attached) disconnectInternal(ctx, c.id);
                removeNodeInternal(ctx, nid);
            },
        });
    }
    for (const gid of ctx.selectedGroups) {
        const g = ctx.groups.get(gid);
        if (g) {
            const gSnap = { id: g.id, label: g.label, x: g.x, y: g.y, width: g.width, height: g.height, color: g.color };
            removeGroupInternal(ctx, gid);
            cmds.push({
                undo: () => addGroupInternal(ctx, gSnap.id, gSnap.label, gSnap.x, gSnap.y, gSnap.width, gSnap.height, gSnap.color),
                redo: () => removeGroupInternal(ctx, gid),
            });
        }
    }
    if (cmds.length) {
        pushCommand(ctx, {
            type: 'deleteSelected',
            undo: () => { for (let i = cmds.length - 1; i >= 0; i--) cmds[i].undo(); },
            redo: () => { for (const c of cmds) c.redo(); },
        });
        onChange(ctx);
    }
    ctx.selectedNodes.clear();
    ctx.selectedConns.clear();
    ctx.selectedGroups.clear();
}

/** Duplicate all selected nodes (offset by gridSize). */
export function duplicateSelected(ctx) {
    const offset = ctx.gridSize;
    const idMap = new Map();
    for (const nid of ctx.selectedNodes) {
        const node = ctx.nodes.get(nid);
        if (!node) continue;
        const newId = ctx.addNode(node.type, node.x + offset, node.y + offset, { ...node.data });
        if (newId) idMap.set(nid, newId);
    }
    // Duplicate connections between selected nodes
    for (const conn of ctx.connections.values()) {
        if (idMap.has(conn.from.nodeId) && idMap.has(conn.to.nodeId)) {
            ctx.connect(idMap.get(conn.from.nodeId), conn.from.portId, idMap.get(conn.to.nodeId), conn.to.portId);
        }
    }
    // Select duplicated nodes
    clearSelection(ctx);
    for (const newId of idMap.values()) selectNode(ctx, newId, true);
}

/** Create a group frame from the current selection bounding box. */
export function groupFromSelection(ctx) {
    if (ctx.selectedNodes.size < 1) return;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const nid of ctx.selectedNodes) {
        const n = ctx.nodes.get(nid);
        if (!n) continue;
        const w = n.el?.offsetWidth || DEFAULTS.nodeFallbackW;
        const h = n.el?.offsetHeight || DEFAULTS.nodeFallbackH;
        minX = Math.min(minX, n.x);
        minY = Math.min(minY, n.y);
        maxX = Math.max(maxX, n.x + w);
        maxY = Math.max(maxY, n.y + h);
    }
    const pad = DEFAULTS.groupPad;
    ctx.addGroup('Group', minX - pad, minY - pad - 24, maxX - minX + pad * 2, maxY - minY + pad * 2 + 24);
}


// ══════════════════════════════════════════════════════════════════
//  Context Menus
// ══════════════════════════════════════════════════════════════════

function showCanvasContextMenu(ctx, e) {
    const vp = getViewportPos(ctx.el, e);
    const canvasPos = screenToCanvas(ctx.panX, ctx.panY, ctx.zoom, vp.x, vp.y);
    const items = [];
    const categories = new Map();
    for (const [type, def] of ctx.nodeTypes) {
        const cat = def.category || 'General';
        if (!categories.has(cat)) categories.set(cat, []);
        categories.get(cat).push({ type, def });
    }
    for (const [cat, entries] of categories) {
        items.push({ type: 'header', label: cat });
        for (const { type, def } of entries) {
            items.push({
                type: 'item', label: `${def.icon || '●'} ${def.label || type}`,
                action: () => ctx.addNode(type, canvasPos.x, canvasPos.y),
            });
        }
    }
    if (ctx.selectedNodes.size > 0) {
        items.push({ type: 'sep' });
        items.push({ type: 'item', label: Icons.svg('folder-plus', { size: 14, strokeWidth: 1.5 }) + ' Group selected', action: () => groupFromSelection(ctx) });
    }
    renderContextMenu(ctx, items, e);
}

function showNodeContextMenu(ctx, nodeId, e) {
    if (!ctx.selectedNodes.has(nodeId)) {
        clearSelection(ctx);
        selectNode(ctx, nodeId, false);
    }
    renderContextMenu(ctx, [
        { type: 'item', label: Icons.svg('trash-2', { size: 14, strokeWidth: 1.5 }) + ' Delete', action: () => deleteSelected(ctx) },
        { type: 'item', label: Icons.svg('copy', { size: 14, strokeWidth: 1.5 }) + ' Duplicate', action: () => duplicateSelected(ctx) },
    ], e);
}

function showConnectionContextMenu(ctx, connId, e) {
    clearSelection(ctx);
    selectConnection(ctx, connId, false);
    renderContextMenu(ctx, [
        { type: 'item', label: Icons.svg('trash-2', { size: 14, strokeWidth: 1.5 }) + ' Delete connection', action: () => ctx.disconnect(connId) },
    ], e);
}

function showGroupContextMenu(ctx, gid, e) {
    clearSelection(ctx);
    selectGroup(ctx, gid, false);
    renderContextMenu(ctx, [
        { type: 'item', label: Icons.svg('trash-2', { size: 14, strokeWidth: 1.5 }) + ' Delete group', action: () => ctx.removeGroup(gid) },
    ], e);
}


// ══════════════════════════════════════════════════════════════════
//  Toolbar
// ══════════════════════════════════════════════════════════════════

/**
 * Handle a toolbar button click.
 * @param {Object} ctx
 * @param {string} action
 * @param {HTMLElement} btn
 */
export function handleToolbarAction(ctx, action, btn) {
    switch (action) {
        case 'undo': ctx.undo(); break;
        case 'redo': ctx.redo(); break;
        case 'zoom-in': ctx.zoomIn(); break;
        case 'zoom-out': ctx.zoomOut(); break;
        case 'zoom-fit': ctx.fitView(); break;
        case 'grid':
            ctx.showGrid = !ctx.showGrid;
            if (btn) razyui(btn).toggleClass('is-active', ctx.showGrid);
            ctx.canvas.find('.nbe-grid').toggleClass('is-visible', ctx.showGrid);
            break;
        case 'minimap': {
            const vis = ctx.minimapWrap.css('display') !== 'none';
            ctx.minimapWrap.css('display', vis ? 'none' : '');
            if (btn) razyui(btn).toggleClass('is-active', !vis);
            if (!vis) scheduleMinimapRender(ctx);
            break;
        }
        case 'group':
            groupFromSelection(ctx);
            break;
        case 'panel':
            ctx.showPanel = !ctx.showPanel;
            ctx.nodePanel.toggleClass('is-hidden', !ctx.showPanel);
            if (btn) razyui(btn).toggleClass('is-active', ctx.showPanel);
            break;
    }
}


// ══════════════════════════════════════════════════════════════════
//  Minimap click navigation
// ══════════════════════════════════════════════════════════════════

function handleMinimapClick(ctx, e) {
    const bounds = getContentBounds(ctx.nodes, ctx.groups);
    if (!bounds) return;
    const cw = ctx.minimapCanvas[0].width;
    const ch = ctx.minimapCanvas[0].height;
    const pad = 40;
    const bw = bounds.w + pad * 2;
    const bh = bounds.h + pad * 2;
    const scale = Math.min(cw / bw, ch / bh);
    const ox = (cw - bw * scale) / 2 - (bounds.x - pad) * scale;
    const oy = (ch - bh * scale) / 2 - (bounds.y - pad) * scale;
    const rect = ctx.minimapCanvas[0].getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;
    const canvasX = (mx - ox) / scale;
    const canvasY = (my - oy) / scale;
    const $vp = ctx.el.find('.nbe-viewport');
    if ($vp.length) {
        const vr = $vp[0].getBoundingClientRect();
        ctx.panX = -canvasX * ctx.zoom + vr.width / 2;
        ctx.panY = -canvasY * ctx.zoom + vr.height / 2;
        applyTransform(ctx);
    }
}
