/**
 * @fileoverview NodeBaseEditor component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — port types, SVG namespace, config defaults
 *   helpers.js   — pure utility functions (geometry, hit-testing, serialization)
 *   state.js     — internal data operations, undo / redo command pattern
 *   view.js      — DOM construction, rendering, canvas / SVG drawing
 *   events.js    — centralised event binding (pointer, keyboard, drag, etc.)
 *
 * @module module/NodeBaseEditor
 */

import { default as razyui } from '../../index.js';
import { sharedResizeObserver } from '../shared/SharedResizeObserver.js';

// ── Sub-module imports ──
import { DEFAULTS } from './constants.js';
import {
    snap as snapVal, nextId, serializeNode,
    resolveId, canConnect as canConnectCheck,
    getContentBounds,
} from './helpers.js';
import {
    buildUI, renderNodePanel, applyTransform,
    updatePortOffsets, scheduleMinimapRender,
} from './view.js';
import {
    pushCommand, undoLast, redoLast, onChange,
    addNodeInternal, removeNodeInternal,
    connectInternal, disconnectInternal,
    autoReplaceInput, addGroupInternal, removeGroupInternal,
    restoreNodePositions,
} from './state.js';
import {
    bindEvents, zoomAtPoint, clearSelection,
    handleToolbarAction,
} from './events.js';


// ══════════════════════════════════════════════════════════════════
//  NodeBaseEditor Class
// ══════════════════════════════════════════════════════════════════

/**
 * NodeBaseEditor — A visual node-based editor component.
 */
const NodeBaseEditor = class {

    // ── Private fields ──────────────────────────────────────────────

    // DOM refs
    /** @type {HTMLElement} */ #el = null;
    /** @type {HTMLElement} */ #canvas = null;
    /** @type {SVGSVGElement} */ #svg = null;
    /** @type {HTMLElement} */ #toolbar = null;
    /** @type {HTMLElement} */ #minimapWrap = null;
    /** @type {HTMLCanvasElement} */ #minimapCanvas = null;
    /** @type {CanvasRenderingContext2D} */ #minimapCtx = null;
    /** @type {HTMLElement} */ #contextMenuEl = null;
    /** @type {HTMLElement} */ #selBoxEl = null;
    /** @type {HTMLElement} */ #nodePanel = null;
    /** @type {boolean} */ #showPanel = true;

    // Config
    /** @type {Object} */ #config = {};

    // Data stores
    /** @type {Map<string,Object>} */ #nodeTypes = new Map();
    /** @type {Map<string,Object>} */ #nodes = new Map();
    /** @type {Map<string,Object>} */ #connections = new Map();
    /** @type {Map<string,Object>} */ #groups = new Map();

    // Selection
    /** @type {Set<string>} */ #selectedNodes = new Set();
    /** @type {Set<string>} */ #selectedConns = new Set();
    /** @type {Set<string>} */ #selectedGroups = new Set();

    // Transform
    /** @type {number} */ #zoom = 1;
    /** @type {number} */ #panX = 0;
    /** @type {number} */ #panY = 0;

    // Grid
    /** @type {number} */ #gridSize = 20;
    /** @type {boolean} */ #snapEnabled = true;
    /** @type {boolean} */ #showGrid = true;

    // Undo / Redo
    /** @type {Array} */ #undoStack = [];
    /** @type {Array} */ #redoStack = [];
    /** @type {number} */ #maxHistory = 100;

    // Drag states
    /** @type {Object|null} */ #wireDrag = null;
    /** @type {Object|null} */ #nodeDrag = null;
    /** @type {Object|null} */ #panDrag = null;
    /** @type {Object|null} */ #boxSelect = null;
    /** @type {Object|null} */ #groupDrag = null;
    /** @type {Object|null} */ #groupResize = null;

    // Misc
    /** @type {number} */ #idCounter = 0;
    /** @type {boolean} */ #spaceHeld = false;
    /** @type {Element|null} */ #resizeObservedEl = null;
    /** @type {number} */ #mmRaf = 0;

    // Bound handlers (for cleanup)
    /** @type {Function} */ #onMouseMove = null;
    /** @type {Function} */ #onMouseUp = null;
    /** @type {Function} */ #onKeyDown = null;
    /** @type {Function} */ #onKeyUp = null;
    /** @type {Function} */ #onWheel = null;

    // Context bridge (cached)
    #_ctx = null;
    #destroyed = false;
    #eventAC = new AbortController();

    /**
     * Lazily create and cache the context bridge that all sub-module
     * functions receive as their first argument. Properties use
     * get / set pairs so the bridge always reflects current private state.
     * @returns {Object}
     */
    #ctx() {
        if (!this.#_ctx) {
            const self = this;
            this.#_ctx = {
                razyui,

                // AbortController signal
                get signal() { return self.#eventAC.signal; },

                // DOM refs
                get el() { return self.#el; },
                get canvas() { return self.#canvas; },
                set canvas(v) { self.#canvas = v; },
                get svg() { return self.#svg; },
                set svg(v) { self.#svg = v; },
                get toolbar() { return self.#toolbar; },
                set toolbar(v) { self.#toolbar = v; },
                get minimapWrap() { return self.#minimapWrap; },
                set minimapWrap(v) { self.#minimapWrap = v; },
                get minimapCanvas() { return self.#minimapCanvas; },
                set minimapCanvas(v) { self.#minimapCanvas = v; },
                get minimapCtx() { return self.#minimapCtx; },
                set minimapCtx(v) { self.#minimapCtx = v; },
                get contextMenuEl() { return self.#contextMenuEl; },
                set contextMenuEl(v) { self.#contextMenuEl = v; },
                get selBoxEl() { return self.#selBoxEl; },
                set selBoxEl(v) { self.#selBoxEl = v; },
                get nodePanel() { return self.#nodePanel; },
                set nodePanel(v) { self.#nodePanel = v; },

                // Config
                get config() { return self.#config; },
                get showPanel() { return self.#showPanel; },
                set showPanel(v) { self.#showPanel = v; },
                get gridSize() { return self.#gridSize; },
                get snapEnabled() { return self.#snapEnabled; },
                get showGrid() { return self.#showGrid; },
                set showGrid(v) { self.#showGrid = v; },
                get maxHistory() { return self.#maxHistory; },

                // Data stores (the Maps/Sets themselves are mutable references)
                get nodeTypes() { return self.#nodeTypes; },
                get nodes() { return self.#nodes; },
                get connections() { return self.#connections; },
                get groups() { return self.#groups; },

                // Selection
                get selectedNodes() { return self.#selectedNodes; },
                get selectedConns() { return self.#selectedConns; },
                get selectedGroups() { return self.#selectedGroups; },

                // Transform
                get zoom() { return self.#zoom; },
                set zoom(v) { self.#zoom = v; },
                get panX() { return self.#panX; },
                set panX(v) { self.#panX = v; },
                get panY() { return self.#panY; },
                set panY(v) { self.#panY = v; },

                // Undo / Redo stacks
                get undoStack() { return self.#undoStack; },
                get redoStack() { return self.#redoStack; },

                // Drag states
                get wireDrag() { return self.#wireDrag; },
                set wireDrag(v) { self.#wireDrag = v; },
                get nodeDrag() { return self.#nodeDrag; },
                set nodeDrag(v) { self.#nodeDrag = v; },
                get panDrag() { return self.#panDrag; },
                set panDrag(v) { self.#panDrag = v; },
                get boxSelect() { return self.#boxSelect; },
                set boxSelect(v) { self.#boxSelect = v; },
                get groupDrag() { return self.#groupDrag; },
                set groupDrag(v) { self.#groupDrag = v; },
                get groupResize() { return self.#groupResize; },
                set groupResize(v) { self.#groupResize = v; },

                // Misc
                get idCounter() { return self.#idCounter; },
                set idCounter(v) { self.#idCounter = v; },
                get spaceHeld() { return self.#spaceHeld; },
                set spaceHeld(v) { self.#spaceHeld = v; },
                get _resizeObservedEl() { return self.#resizeObservedEl; },
                set _resizeObservedEl(v) { self.#resizeObservedEl = v; },
                get mmRaf() { return self.#mmRaf; },
                set mmRaf(v) { self.#mmRaf = v; },

                // Bound handlers
                get onMouseMove() { return self.#onMouseMove; },
                set onMouseMove(v) { self.#onMouseMove = v; },
                get onMouseUp() { return self.#onMouseUp; },
                set onMouseUp(v) { self.#onMouseUp = v; },
                get onKeyDown() { return self.#onKeyDown; },
                set onKeyDown(v) { self.#onKeyDown = v; },
                get onKeyUp() { return self.#onKeyUp; },
                set onKeyUp(v) { self.#onKeyUp = v; },
                get onWheel() { return self.#onWheel; },
                set onWheel(v) { self.#onWheel = v; },

                // Methods (bound once)
                addNode:    (...args) => self.addNode(...args),
                removeNode: (...args) => self.removeNode(...args),
                connect:    (...args) => self.connect(...args),
                disconnect: (...args) => self.disconnect(...args),
                addGroup:   (...args) => self.addGroup(...args),
                removeGroup:(...args) => self.removeGroup(...args),
                undo:       ()        => self.undo(),
                redo:       ()        => self.redo(),
                zoomIn:     ()        => self.zoomIn(),
                zoomOut:    ()        => self.zoomOut(),
                fitView:    ()        => self.fitView(),
                resetZoom:  ()        => self.resetZoom(),
                handleToolbarAction: (action, btn) => handleToolbarAction(self.#ctx(), action, btn),
            };
        }
        return this.#_ctx;
    }


    // ── Constructor ─────────────────────────────────────────────────

    /**
     * Create a NodeBaseEditor.
     * @param {string|HTMLElement} selector - Container selector or element.
     * @param {Object} [config={}]
     */
    constructor(selector, config = {}) {
        const el = razyui(selector);
        if (!el.length) {
            console.warn('NodeBaseEditor: element not found \u2192', selector);
            return;
        }
        this.#el = el;
        this.#config = config;
        this.#gridSize = config.gridSize || DEFAULTS.gridSize;
        this.#snapEnabled = config.snapToGrid ?? DEFAULTS.snapToGrid;
        this.#showGrid = config.showGrid ?? DEFAULTS.showGrid;
        this.#showPanel = config.showPanel ?? DEFAULTS.showPanel;
        this.#maxHistory = config.maxHistory || DEFAULTS.maxHistory;

        // Register any pre-defined node types
        if (config.nodeTypes) {
            for (const [type, def] of Object.entries(config.nodeTypes)) {
                this.#nodeTypes.set(type, def);
            }
        }

        const ctx = this.#ctx();
        buildUI(ctx);
        bindEvents(ctx);

        if (config.data) this.setData(config.data);
    }


    // ── Node Type Registry ──────────────────────────────────────────

    /**
     * Register a node type definition.
     * @param {string} type - Unique type key.
     * @param {Object} def  - { label, icon, category, color, inputs:[], outputs:[] }
     */
    registerNodeType(type, def) {
        this.#nodeTypes.set(type, def);
        renderNodePanel(this.#ctx());
    }

    /** 
     * Unregister a node type. 
     * @param {string} type - The type key to unregister.
     */
    unregisterNodeType(type) {
        this.#nodeTypes.delete(type);
        renderNodePanel(this.#ctx());
    }


    // ── Node CRUD ───────────────────────────────────────────────────

    /**
     * Add a new node to the canvas.
     * @param {string} type - The type of node to add.
     * @param {number} x - The x-coordinate.
     * @param {number} y - The y-coordinate.
     * @param {Object} [data={}] - Initial data for the node.
     * @returns {string|null} The new node id, or null if type is unknown.
     */
    addNode(type, x, y, data = {}) {
        const ctx = this.#ctx();
        const def = this.#nodeTypes.get(type);
        if (!def) { console.warn('NodeBaseEditor: unknown node type \u2192', type); return null; }
        const id = nextId(ctx, 'node');
        const sX = snapVal(x, this.#gridSize, this.#snapEnabled);
        const sY = snapVal(y, this.#gridSize, this.#snapEnabled);
        const node = addNodeInternal(ctx, id, type, sX, sY, def.label || type, data);
        pushCommand(ctx, {
            type: 'addNode',
            nodeId: id,
            redo: () => addNodeInternal(ctx, id, type, node.x, node.y, node.label, { ...node.data }),
            undo: () => removeNodeInternal(ctx, id),
        });
        onChange(ctx);
        return id;
    }

    /**
     * Remove a node (with undo support).
     * @param {string} id - The ID of the node to remove.
     */
    removeNode(id) {
        const ctx = this.#ctx();
        const node = this.#nodes.get(id);
        if (!node) return;
        // Snapshot connections attached to this node
        const attachedConns = [];
        for (const conn of this.#connections.values()) {
            if (conn.from.nodeId === id || conn.to.nodeId === id) {
                attachedConns.push({ ...conn, from: { ...conn.from }, to: { ...conn.to } });
            }
        }
        const snapshot = serializeNode(node);
        for (const c of attachedConns) disconnectInternal(ctx, c.id);
        removeNodeInternal(ctx, id);
        pushCommand(ctx, {
            type: 'removeNode',
            nodeId: id,
            undo: () => {
                addNodeInternal(ctx, snapshot.id, snapshot.type, snapshot.x, snapshot.y, snapshot.label, { ...snapshot.data });
                for (const c of attachedConns) {
                    connectInternal(ctx, c.id, c.from.nodeId, c.from.portId, c.to.nodeId, c.to.portId);
                }
            },
            redo: () => {
                for (const c of attachedConns) disconnectInternal(ctx, c.id);
                removeNodeInternal(ctx, id);
            },
        });
        onChange(ctx);
    }


    // ── Connection CRUD ─────────────────────────────────────────────

    /**
     * Create a connection between two ports (with undo).
     * @param {string} fromNodeId
     * @param {string} fromPortId
     * @param {string} toNodeId
     * @param {string} toPortId
     * @returns {string|null} Connection id, or null on failure.
     */
    connect(fromNodeId, fromPortId, toNodeId, toPortId) {
        const ctx = this.#ctx();
        if (!canConnectCheck(this.#nodes, this.#connections, this.#config, fromNodeId, fromPortId, toNodeId, toPortId)) return null;
        autoReplaceInput(ctx, toNodeId, toPortId);
        const id = nextId(ctx, 'conn');
        connectInternal(ctx, id, fromNodeId, fromPortId, toNodeId, toPortId);
        pushCommand(ctx, {
            type: 'connect',
            connId: id,
            redo: () => connectInternal(ctx, id, fromNodeId, fromPortId, toNodeId, toPortId),
            undo: () => disconnectInternal(ctx, id),
        });
        onChange(ctx);
        return id;
    }

    /**
     * Disconnect (remove) a connection (with undo).
     * @param {string} id
     */
    disconnect(id) {
        const ctx = this.#ctx();
        const conn = this.#connections.get(id);
        if (!conn) return;
        const snap = { id: conn.id, from: { ...conn.from }, to: { ...conn.to } };
        disconnectInternal(ctx, id);
        pushCommand(ctx, {
            type: 'disconnect',
            connId: id,
            undo: () => connectInternal(ctx, snap.id, snap.from.nodeId, snap.from.portId, snap.to.nodeId, snap.to.portId),
            redo: () => disconnectInternal(ctx, id),
        });
        onChange(ctx);
    }


    // ── Group CRUD ──────────────────────────────────────────────────

    /**
     * Add a group frame (with undo).
     * @param {string} label - The label for the group.
     * @param {number} x - The x-coordinate.
     * @param {number} y - The y-coordinate.
     * @param {number} width - The width of the group.
     * @param {number} height - The height of the group.
     * @param {string} [color='#e3f2fd'] - The background color of the group.
     * @returns {string} group id
     */
    addGroup(label, x, y, width, height, color = '#e3f2fd') {
        const ctx = this.#ctx();
        const id = nextId(ctx, 'grp');
        addGroupInternal(ctx, id, label, x, y, width, height, color);
        pushCommand(ctx, {
            type: 'addGroup',
            groupId: id,
            redo: () => addGroupInternal(ctx, id, label, x, y, width, height, color),
            undo: () => removeGroupInternal(ctx, id),
        });
        onChange(ctx);
        return id;
    }

    /**
     * Remove a group (with undo).
     * @param {string} id - The ID of the group to remove.
     */
    removeGroup(id) {
        const ctx = this.#ctx();
        const g = this.#groups.get(id);
        if (!g) return;
        const snap = { id: g.id, label: g.label, x: g.x, y: g.y, width: g.width, height: g.height, color: g.color };
        removeGroupInternal(ctx, id);
        pushCommand(ctx, {
            type: 'removeGroup',
            undo: () => addGroupInternal(ctx, snap.id, snap.label, snap.x, snap.y, snap.width, snap.height, snap.color),
            redo: () => removeGroupInternal(ctx, id),
        });
        onChange(ctx);
    }


    // ── Undo / Redo ─────────────────────────────────────────────────

    /** Undo the last command. */
    undo() { undoLast(this.#ctx()); }

    /** Redo the last undone command. */
    redo() { redoLast(this.#ctx()); }


    // ── Zoom Controls ───────────────────────────────────────────────

    /** Zoom in by one step centred on the viewport. */
    zoomIn() {
        const $vp = this.#el.find('.nbe-viewport');
        const r = $vp[0].getBoundingClientRect();
        zoomAtPoint(this.#ctx(), r.width / 2, r.height / 2, this.#zoom * DEFAULTS.zoomStep);
    }

    /** Zoom out by one step centred on the viewport. */
    zoomOut() {
        const $vp = this.#el.find('.nbe-viewport');
        const r = $vp[0].getBoundingClientRect();
        zoomAtPoint(this.#ctx(), r.width / 2, r.height / 2, this.#zoom / DEFAULTS.zoomStep);
    }

    /** Reset zoom to 100%. */
    resetZoom() {
        const $vp = this.#el.find('.nbe-viewport');
        const r = $vp[0].getBoundingClientRect();
        zoomAtPoint(this.#ctx(), r.width / 2, r.height / 2, 1);
    }

    /** Fit all content into the viewport. */
    fitView() {
        const ctx = this.#ctx();
        const bounds = getContentBounds(this.#nodes, this.#groups);
        if (!bounds) return;
        const $vp = this.#el.find('.nbe-viewport');
        const r = $vp[0].getBoundingClientRect();
        const pad = DEFAULTS.fitPad;
        const zx = (r.width - pad * 2) / bounds.w;
        const zy = (r.height - pad * 2) / bounds.h;
        const z = Math.min(zx, zy, 1);
        const minZ = this.#config.minZoom || DEFAULTS.minZoom;
        const maxZ = this.#config.maxZoom || DEFAULTS.maxZoom;
        this.#zoom = Math.min(maxZ, Math.max(minZ, z));
        this.#panX = r.width / 2 - (bounds.x + bounds.w / 2) * this.#zoom;
        this.#panY = r.height / 2 - (bounds.y + bounds.h / 2) * this.#zoom;
        applyTransform(ctx);
        // Recalculate port offsets now that zoom changed
        for (const node of this.#nodes.values()) updatePortOffsets(ctx, node);
    }


    // ── Data Import / Export ────────────────────────────────────────

    /**
     * Export the current editor state as a JSON-serialisable object.
     * @returns {{ nodes:Array, connections:Array, groups:Array }} The exported data.
     */
    getData() {
        const nodes = [];
        for (const n of this.#nodes.values()) nodes.push(serializeNode(n));
        const connections = [];
        for (const c of this.#connections.values()) {
            connections.push({ id: c.id, from: { ...c.from }, to: { ...c.to } });
        }
        const groups = [];
        for (const g of this.#groups.values()) {
            groups.push({ id: g.id, label: g.label, x: g.x, y: g.y, width: g.width, height: g.height, color: g.color });
        }
        return { nodes, connections, groups };
    }

    /**
     * Load editor state from a data object. Clears existing content.
     * @param {{ nodes?:Array, connections?:Array, groups?:Array }} data - The data to load.
     */
    setData(data) {
        const ctx = this.#ctx();
        // Clear everything
        for (const c of [...this.#connections.keys()]) disconnectInternal(ctx, c);
        for (const n of [...this.#nodes.keys()]) removeNodeInternal(ctx, n);
        for (const g of [...this.#groups.keys()]) removeGroupInternal(ctx, g);
        this.#undoStack.length = 0;
        this.#redoStack.length = 0;
        this.#idCounter = 0;

        // Import groups
        if (data.groups) {
            for (const g of data.groups) {
                resolveId(ctx, g.id);
                addGroupInternal(ctx, g.id, g.label, g.x, g.y, g.width, g.height, g.color || '#e3f2fd');
            }
        }

        // Import nodes
        if (data.nodes) {
            for (const n of data.nodes) {
                resolveId(ctx, n.id);
                addNodeInternal(ctx, n.id, n.type, n.x, n.y, n.label, n.data || {});
            }
        }

        // Import connections (use requestAnimationFrame to ensure port offsets are ready)
        requestAnimationFrame(() => {
            for (const node of this.#nodes.values()) updatePortOffsets(ctx, node);
            if (data.connections) {
                for (const c of data.connections) {
                    resolveId(ctx, c.id);
                    connectInternal(ctx, c.id, c.from.nodeId, c.from.portId, c.to.nodeId, c.to.portId);
                }
            }
            scheduleMinimapRender(ctx);
        });
    }


    // ── getControl ──────────────────────────────────────────────────

    /**
     * Return the public API for external callers.
     * @returns {Object}
     */
    getControl() {
        const ctx = this.#ctx();
        return {
            registerNodeType: (type, def) => this.registerNodeType(type, def),
            unregisterNodeType: (type) => this.unregisterNodeType(type),
            addNode: (type, x, y, data) => this.addNode(type, x, y, data),
            removeNode: (id) => this.removeNode(id),
            connect: (from, fromPort, to, toPort) => this.connect(from, fromPort, to, toPort),
            disconnect: (id) => this.disconnect(id),
            addGroup: (label, x, y, w, h, color) => this.addGroup(label, x, y, w, h, color),
            removeGroup: (id) => this.removeGroup(id),
            getData: () => this.getData(),
            setData: (d) => this.setData(d),
            undo: () => this.undo(),
            redo: () => this.redo(),
            zoomIn: () => this.zoomIn(),
            zoomOut: () => this.zoomOut(),
            fitView: () => this.fitView(),
            resetZoom: () => this.resetZoom(),
            togglePanel: () => handleToolbarAction(ctx, 'panel', this.#toolbar.find('[data-action="panel"]')[0]),
            clearSelection: () => clearSelection(ctx),
            getSelected: () => ({
                nodes: [...this.#selectedNodes],
                connections: [...this.#selectedConns],
                groups: [...this.#selectedGroups],
            }),
            destroy: () => this.destroy(),
            get element() { return this.#el[0]; },
            get destroyed() { return this.#destroyed; },
        };
    }


    // ── Destroy ─────────────────────────────────────────────────────

    /** Tear down the editor — remove events, DOM, and observers. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        const $viewport = this.#el.find('.nbe-viewport');
        if ($viewport.length) $viewport[0].removeEventListener('wheel', this.#onWheel);
        if (this.#resizeObservedEl) {
            sharedResizeObserver.unobserve(this.#resizeObservedEl);
            this.#resizeObservedEl = null;
        }
        if (this.#mmRaf) cancelAnimationFrame(this.#mmRaf);
        this.#el.html('');
        this.#el.removeClass('node-base-editor nbe-root');
        this.#nodes.clear();
        this.#connections.clear();
        this.#groups.clear();
        this.#nodeTypes.clear();
        this.#undoStack.length = 0;
        this.#redoStack.length = 0;
    }
};

export default NodeBaseEditor;
