/**
 * @fileoverview NodeBaseEditor helpers — pure utility functions
 * (geometry, hit-testing, serialization, validation).
 *
 * @module module/NodeBaseEditor/helpers
 */

import razyui from '../../index.js';
import { PORT_TYPES, DEFAULTS } from './constants.js';

// ══════════════════════════════════════════════════════════════════
//  Port helpers
// ══════════════════════════════════════════════════════════════════

/**
 * Check whether two port types can be connected.
 * @param {string} outType - Source port type.
 * @param {string} inType  - Target port type.
 * @returns {boolean}
 */
export function portsCompatible(outType, inType) {
    if (outType === inType) return true;
    if (outType === 'any' || inType === 'any') return true;
    if (outType === 'flow' || inType === 'flow') return false;
    return false;
}

/**
 * Return the display colour for a port type.
 * @param {string} type
 * @returns {string}
 */
export function portColor(type) {
    return PORT_TYPES[type]?.color || PORT_TYPES.any.color;
}


// ══════════════════════════════════════════════════════════════════
//  Geometry / transform helpers
// ══════════════════════════════════════════════════════════════════

/**
 * Compute a horizontal cubic bézier path string.
 * @param {number} x1
 * @param {number} y1
 * @param {number} x2
 * @param {number} y2
 * @returns {string} SVG path `d` attribute.
 */
export function bezier(x1, y1, x2, y2) {
    const dx = Math.abs(x2 - x1);
    const off = Math.max(DEFAULTS.bezierMinOffset, dx * 0.5);
    return `M ${x1} ${y1} C ${x1 + off} ${y1}, ${x2 - off} ${y2}, ${x2} ${y2}`;
}

/**
 * Convert screen (viewport-relative) coordinates to canvas coordinates.
 * @param {number} panX
 * @param {number} panY
 * @param {number} zoom
 * @param {number} sx - Screen X relative to viewport.
 * @param {number} sy - Screen Y relative to viewport.
 * @returns {{x:number, y:number}}
 */
export function screenToCanvas(panX, panY, zoom, sx, sy) {
    return {
        x: (sx - panX) / zoom,
        y: (sy - panY) / zoom,
    };
}

/**
 * Get the viewport-relative position from a client mouse event.
 * @param {HTMLElement} el - Root editor element.
 * @param {MouseEvent} e
 * @returns {{x:number, y:number}}
 */
export function viewportPos(el, e) {
    const $vp = el.find('.nbe-viewport');
    if (!$vp[0]) return { x: 0, y: 0 };
    const r = $vp[0].getBoundingClientRect();
    return { x: e.clientX - r.left, y: e.clientY - r.top };
}

/**
 * Snap a value to the grid if snapping is enabled.
 * @param {number} v
 * @param {number} gridSize
 * @param {boolean} snapEnabled
 * @returns {number}
 */
export function snap(v, gridSize, snapEnabled) {
    return snapEnabled ? Math.round(v / gridSize) * gridSize : v;
}


// ══════════════════════════════════════════════════════════════════
//  ID / DOM helpers
// ══════════════════════════════════════════════════════════════════

/**
 * Generate a unique ID with the given prefix.
 * Mutates `ctx.idCounter`.
 * @param {Object} ctx
 * @param {string} [prefix='n']
 * @returns {string}
 */
export function nextId(ctx, prefix = 'n') {
    ctx.idCounter++;
    return prefix + '-' + ctx.idCounter;
}

/**
 * Ensure the internal counter stays above any imported id.
 * @param {Object} ctx
 * @param {string} id
 */
export function resolveId(ctx, id) {
    if (typeof id === 'string') {
        const match = id.match(/(\d+)$/);
        if (match) {
            const num = parseInt(match[1], 10);
            if (num >= ctx.idCounter) ctx.idCounter = num + 1;
        }
    }
}

/**
 * Create a plain HTML element with a class.
 * @param {string} tag
 * @param {string} [cls]
 * @returns {Elements}
 */
export function mk(tag, cls) {
    return razyui.el(tag, cls ? { className: cls } : undefined);
}

/**
 * HTML-escape a string.
 * @param {string} str
 * @returns {string}
 */
export function escHtml(str) {
    return razyui.el('div', { textContent: str }).html();
}


// ══════════════════════════════════════════════════════════════════
//  Serialization
// ══════════════════════════════════════════════════════════════════

/**
 * Serialise a node object to a plain object (for data export / undo snapshot).
 * @param {Object} node
 * @returns {Object}
 */
export function serializeNode(node) {
    return {
        id: node.id,
        type: node.type,
        label: node.label,
        x: node.x,
        y: node.y,
        data: { ...node.data },
    };
}


// ══════════════════════════════════════════════════════════════════
//  Bounds / hit-testing
// ══════════════════════════════════════════════════════════════════

/**
 * Get the bounding rectangle of all content (nodes + groups).
 * @param {Map} nodes
 * @param {Map} groups
 * @returns {{x:number,y:number,w:number,h:number}|null}
 */
export function getContentBounds(nodes, groups) {
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const n of nodes.values()) {
        const w = n.el?.offsetWidth || DEFAULTS.nodeFallbackW;
        const h = n.el?.offsetHeight || DEFAULTS.nodeFallbackH;
        minX = Math.min(minX, n.x);
        minY = Math.min(minY, n.y);
        maxX = Math.max(maxX, n.x + w);
        maxY = Math.max(maxY, n.y + h);
    }
    for (const g of groups.values()) {
        minX = Math.min(minX, g.x);
        minY = Math.min(minY, g.y);
        maxX = Math.max(maxX, g.x + g.width);
        maxY = Math.max(maxY, g.y + g.height);
    }
    if (minX === Infinity) return null;
    return { x: minX, y: minY, w: maxX - minX, h: maxY - minY };
}

/**
 * Get the canvas-space centre of a port dot.
 * @param {Map} nodes
 * @param {string} nodeId
 * @param {string} portId
 * @returns {{x:number, y:number}|null}
 */
export function getPortPos(nodes, nodeId, portId) {
    const node = nodes.get(nodeId);
    if (!node) return null;
    const port = node.inputPorts.get(portId) || node.outputPorts.get(portId);
    if (!port) return null;
    return { x: node.x + port.localX, y: node.y + port.localY };
}

/**
 * Find the nearest compatible port dot to a screen position.
 * @param {Map} nodes
 * @param {Object} wireDrag - Current wire-drag state.
 * @param {number} cx - Client X.
 * @param {number} cy - Client Y.
 * @param {string} excludeNodeId
 * @param {boolean} wantInput
 * @returns {{nodeId:string, portId:string}|null}
 */
export function findPortNearPoint(nodes, wireDrag, cx, cy, excludeNodeId, wantInput) {
    let best = null;
    let bestDist = DEFAULTS.portSearchRadius;
    const fromNode = nodes.get(wireDrag?.fromNodeId);
    const fromPort = wireDrag?.isOutput
        ? fromNode?.outputPorts.get(wireDrag?.fromPortId)
        : fromNode?.inputPorts.get(wireDrag?.fromPortId);
    const srcType = fromPort?.type || 'any';
    for (const node of nodes.values()) {
        if (node.id === excludeNodeId) continue;
        const ports = wantInput ? node.inputPorts : node.outputPorts;
        for (const port of ports.values()) {
            if (!portsCompatible(srcType, port.type)) continue;
            const el = port.dot[0] || port.dot;
            const r = el.getBoundingClientRect();
            const dx = cx - (r.left + r.width / 2);
            const dy = cy - (r.top + r.height / 2);
            const dist = Math.hypot(dx, dy);
            if (dist < bestDist) {
                bestDist = dist;
                best = { nodeId: node.id, portId: port.name };
            }
        }
    }
    return best;
}

/**
 * Get nodes whose centres lie inside a group.
 * @param {Map} nodes
 * @param {Map} groups
 * @param {string} gid
 * @returns {string[]}
 */
export function nodesInGroup(nodes, groups, gid) {
    const g = groups.get(gid);
    if (!g) return [];
    const ids = [];
    for (const n of nodes.values()) {
        const cx = n.x + (n.el?.offsetWidth || DEFAULTS.nodeFallbackW) / 2;
        const cy = n.y + (n.el?.offsetHeight || DEFAULTS.nodeFallbackH) / 2;
        if (cx >= g.x && cx <= g.x + g.width && cy >= g.y && cy <= g.y + g.height) {
            ids.push(n.id);
        }
    }
    return ids;
}


// ══════════════════════════════════════════════════════════════════
//  Connection validation
// ══════════════════════════════════════════════════════════════════

/**
 * BFS: would adding fromNodeId→toNodeId create a cycle?
 * @param {Map} connections
 * @param {string} fromNodeId
 * @param {string} toNodeId
 * @returns {boolean}
 */
export function wouldCreateCycle(connections, fromNodeId, toNodeId) {
    const visited = new Set();
    const queue = [toNodeId];
    while (queue.length) {
        const cur = queue.shift();
        if (cur === fromNodeId) return true;
        if (visited.has(cur)) continue;
        visited.add(cur);
        for (const c of connections.values()) {
            if (c.from.nodeId === cur) queue.push(c.to.nodeId);
        }
    }
    return false;
}

/**
 * Check whether a proposed connection is allowed.
 * @param {Map} nodes
 * @param {Map} connections
 * @param {Object} config
 * @param {string} fromNodeId
 * @param {string} fromPortId
 * @param {string} toNodeId
 * @param {string} toPortId
 * @returns {boolean}
 */
export function canConnect(nodes, connections, config, fromNodeId, fromPortId, toNodeId, toPortId) {
    if (fromNodeId === toNodeId) return false;
    const fromNode = nodes.get(fromNodeId);
    const toNode = nodes.get(toNodeId);
    if (!fromNode || !toNode) return false;
    const outPort = fromNode.outputPorts.get(fromPortId);
    const inPort = toNode.inputPorts.get(toPortId);
    if (!outPort || !inPort) return false;
    if (!portsCompatible(outPort.type, inPort.type)) return false;
    // Duplicate check
    for (const c of connections.values()) {
        if (c.from.nodeId === fromNodeId && c.from.portId === fromPortId &&
            c.to.nodeId === toNodeId && c.to.portId === toPortId) return false;
    }
    // Cycle check
    if (!(config.allowCycles ?? false)) {
        if (wouldCreateCycle(connections, fromNodeId, toNodeId)) return false;
    }
    return true;
}
